async function concurrencyLimit<T>(
  tasks: (() => Promise<T>)[],
  limit: number
): Promise<T[]> {
  const results: T[] = [];
  const active = new Set<Promise<void>>();

  for (let i = 0; i < tasks.length; i++) {
    const task = tasks[i];
    const p = task()
      .then((result) => {
        results[i] = result;
      })
      .catch((err) => {
        results[i] = err as T;
      })
      .finally(() => {
        active.delete(p);
      });

    active.add(p);

    if (active.size >= limit) {
      await Promise.race(active);
    }
  }

  await Promise.allSettled(active);
  return results;
}

