// Debounce
function debounce(fn, delay, options = {}) {
  let timer = null;
  let lastArgs = null;
  const { leading = false, trailing = true } = options;

  function debounced(...args) {
    const isFirstCall = !timer && leading;
    lastArgs = args;

    if (timer) clearTimeout(timer);

    if (isFirstCall) {
      fn.apply(this, lastArgs);
    }

    timer = setTimeout(() => {
      if (trailing && lastArgs) {
        fn.apply(this, lastArgs);
      }
      timer = null;
      lastArgs = null;
    }, delay);
  }

  debounced.cancel = () => {
    clearTimeout(timer);
    timer = null;
    lastArgs = null;
  };

  return debounced;
}

// Throttle
function throttle(fn, interval, options = {}) {
  let lastTime = 0;
  let timer = null;
  const { leading = true, trailing = true } = options;

  function throttled(...args) {
    const now = Date.now();
    const isLeading = leading && now - lastTime >= interval;

    if (isLeading) {
      lastTime = now;
      fn.apply(this, args);
    }

    if (!timer && trailing) {
      timer = setTimeout(() => {
        lastTime = Date.now();
        timer = null;
        fn.apply(this, args);
      }, interval - (now - lastTime));
    }
  }

  throttled.cancel = () => {
    clearTimeout(timer);
    timer = null;
    lastTime = 0;
  };

  return throttled;
}

