const buildPath = (parents: Map<string, string | null>, target: string): string[] => {
  const path: string[] = [];
  let current: string | null = target;
  while (current !== null) {
    path.push(current);          // O(1) amortized
    current = parents.get(current) ?? null;
  }
  return path.reverse();         // single O(n)
};

