class MinHeap {
  private heap: { task: Function; priority: number; executeAt: number }[] = [];

  push(item: { task: Function; priority: number; executeAt: number }) {
    this.heap.push(item);
    this.bubbleUp(this.heap.length - 1);
  }

  pop() {
    const top = this.heap[0];
    const last = this.heap.pop();
    if (this.heap.length > 0 && last) {
      this.heap[0] = last;
      this.sinkDown(0);
    }
    return top;
  }

  private bubbleUp(i: number) {
    while (i > 0) {
      const parent = Math.floor((i - 1) / 2);
      if (this.heap[i].priority < this.heap[parent].priority) {
        [this.heap[i], this.heap[parent]] = [this.heap[parent], this.heap[i]];
        i = parent;
      } else break;
    }
  }

  private sinkDown(i: number) {
    while (true) {
      let smallest = i;
      const left = 2 * i + 1;
      const right = 2 * i + 2;
      if (left < this.heap.length && this.heap[left].priority < this.heap[smallest].priority) smallest = left;
      if (right < this.heap.length && this.heap[right].priority < this.heap[smallest].priority) smallest = right;
      if (smallest !== i) {
        [this.heap[i], this.heap[smallest]] = [this.heap[smallest], this.heap[i]];
        i = smallest;
      } else break;
    }
  }

  get size() { return this.heap.length; }
}

function promiseAll(promises) {
  return new Promise((resolve, reject) => {
    const items = Array.from(promises);
    const results = new Array(items.length);
    let completed = 0;
    let rejected = false;

    if (items.length === 0) {
      resolve(results);
      return;
    }

    items.forEach((promise, index) => {
      Promise.resolve(promise).then(
        (value) => {
          if (rejected) return;
          results[index] = value;
          completed++;
          if (completed === items.length) {
            resolve(results);
          }
        },
        (error) => {
          if (rejected) return;
          rejected = true;
          reject(error);
        }
      );
    });
  });
}

function maxSlidingWindow(nums, k) {
  const deque = []; // индексы, значения убывают
  const result = [];

  for (let i = 0; i < nums.length; i++) {
    // Удаляем элементы, вышедшие за границу окна
    while (deque.length && deque[0] <= i - k) {
      deque.shift();
    }

    // Удаляем с хвоста все элементы меньше текущего
    while (deque.length && nums[deque[deque.length - 1]] <= nums[i]) {
      deque.pop();
    }

    deque.push(i);

    // Начинаем записывать результат, когда окно полностью заполнено
    if (i >= k - 1) {
      result.push(nums[deque[0]]);
    }
  }

  return result;
}

